#include<bits/stdc++.h>
using namespace std;

#define ll long long

ll n,t,v[10000001],w[10001000],dp[10000001];

int main(){
	cin>>n>>t;
	for(int i=1;i<=n;i++){
		cin>>w[i]>>v[i];
	}
	for(int i=1;i<=n;i++){
		for(int j=w[i];j<=t;j++){
			dp[j]=max(dp[j],dp[j-w[i]]+v[i]);
		}
	}cout<<dp[t];
	return 0;
}
